@namespace Components

<div class="checkout-wizard">
    @switch (_step)
    {
        case WizardStep.Shipping:
            <ShippingStep Shipping="_order.Shipping" OnNext="HandleShippingComplete" />
            break;

        case WizardStep.Payment:
            <PaymentStep Payment="_order.Payment"
                         OnBack="HandleBackToShipping"
                         OnPlaceOrder="HandlePlaceOrder" />
            break;
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private WizardStep _step = WizardStep.Shipping;

    private enum WizardStep { Shipping, Payment }

    private void HandleShippingComplete()
    {
        _step = WizardStep.Payment;
    }

    private void HandleBackToShipping()
    {
        _step = WizardStep.Shipping;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace Components
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input @bind="Shipping.Name" />
    </label>

    <label>
        Address
        <input @bind="Shipping.Address" @oninput="OnFieldChanged" />
    </label>

    <label>
        City
        <input @bind="Shipping.City" @oninput="OnFieldChanged" />
    </label>

    <label>
        Zip Code
        <input @bind="Shipping.ZipCode" @oninput="OnFieldChanged" />
    </label>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="validation-error">@_errorMessage</div>
    }
</fieldset>

<button disabled="@_isValidating" @onclick="HandleNext">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    private void OnFieldChanged()
    {
        // User changed a field — cancel any in-flight validation so a
        // subsequent "Next" click starts fresh.
        CancelPendingValidation();
    }

    private async Task HandleNext()
    {
        _errorMessage = null;

        // Cancel any previous validation before starting a new one.
        CancelPendingValidation();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

